Operating reserves
Months of expenses covered by net assets — the sector’s standard solvency gauge. Three months is the commonly cited minimum; the red band marks organizations below it.

reserveData = fin.filter(d =&gt; d.months_reserves != null && isFinite(d.months_reserves))







reserveBuckets = {
  const buckets = [
    {label: "Negative", test: d =&gt; d.months_reserves &lt; 0, atRisk: true},
    {label: "0–3 months", test: d =&gt; d.months_reserves &gt;= 0 && d.months_reserves &lt; 3, atRisk: true},
    {label: "3–6 months", test: d =&gt; d.months_reserves &gt;= 3 && d.months_reserves &lt; 6, atRisk: false},
    {label: "6–12 months", test: d =&gt; d.months_reserves &gt;= 6 && d.months_reserves &lt; 12, atRisk: false},
    {label: "1–3 years", test: d =&gt; d.months_reserves &gt;= 12 && d.months_reserves &lt; 36, atRisk: false},
    {label: "3+ years", test: d =&gt; d.months_reserves &gt;= 36, atRisk: false}
  ];
  return buckets.map(b =&gt; ({bucket: b.label, atRisk: b.atRisk, n: reserveData.filter(b.test).length}));
}







Plot.plot({
  height: 300,
  width: 900,
  marginLeft: 55,
  marginBottom: 45,
  style: {fontSize: "13px"},
  x: {label: "Net assets as months of expenses", labelAnchor: "center", domain: reserveBuckets.map(d =&gt; d.bucket)},
  y: {label: "Organizations", grid: true},
  marks: [
    Plot.barY(reserveBuckets, {
      x: "bucket",
      y: "n",
      fill: d =&gt; d.atRisk ? GU.red : GU.s1,
      rx: 3,
      insetLeft: 5,
      insetRight: 5,
      tip: true,
      title: d =&gt; `${d.bucket}: ${fnum(d.n)} organizations (${fpct(d.n / reserveData.length * 100)})`
    }),
    Plot.textY(reserveBuckets, {
      x: "bucket", y: "n", text: d =&gt; fnum(d.n), dy: -8, fill: GU.ink, fontSize: 12
    }),
    Plot.ruleY([0], {stroke: "#c3c2b7"})
  ]
})







md`&lt;span style="color:${GU.muted}; font-size:0.85rem;"&gt;&lt;span style="color:${GU.red}"&gt;&#9632;&lt;/span&gt; below the three-month minimum cushion (${fpct(d3.mean(reserveData, d =&gt; d.months_reserves &lt; 3) * 100)} of organizations).&lt;/span&gt;`

Financial detail: every covered organization

viewof finCounty = Inputs.select(
  ["All counties"].concat(Array.from(new Set(fin.map(d =&gt; d.county))).sort()),
  {label: "County"}
)







viewof finSearch = Inputs.search(
  fin.filter(d =&gt; finCounty === "All counties" || d.county === finCounty),
  {placeholder: "Search names…", columns: ["name", "city"]}
)







Inputs.table(
  finSearch
    .sort((a, b) =&gt; d3.descending(a.totrevenue, b.totrevenue))
    .map(d =&gt; ({
      Name: d.name,
      County: d.county,
      FY: String(d.tax_prd_yr),
      Revenue: fmoney(d.totrevenue),
      Expenses: fmoney(d.totfuncexpns),
      "Margin": d.margin != null ? fpct(d.margin * 100) : "—",
      "Months reserves": d.months_reserves != null && isFinite(d.months_reserves) ? d3.format(".1f")(d.months_reserves) : "—",
      "Contrib. share": d.contrib_share != null ? fpct(Math.min(Math.max(d.contrib_share, 0), 1) * 100) : "—"
    })),
  {rows: 15, layout: "auto"}
)







Source: IRS Form 990/990-EZ extracts via ProPublica Nonprofit Explorer API, latest filing per organization (2021 or later).

Size distribution
Revenue as most recently reported to the IRS. The majority of registered nonprofits — small clubs, PTAs, granges, all-volunteer groups — report no revenue at all (they fall below filing thresholds), so the chart below covers the 1,540 organizations with a reported revenue figure.

sizeBuckets = {
  const withRev = orgs.filter(d =&gt; d.revenue &gt; 0);
  const buckets = [
    {label: "Under $100k", test: d =&gt; d.revenue &lt; 1e5},
    {label: "$100k–$500k", test: d =&gt; d.revenue &gt;= 1e5 && d.revenue &lt; 5e5},
    {label: "$500k–$1M", test: d =&gt; d.revenue &gt;= 5e5 && d.revenue &lt; 1e6},
    {label: "$1M–$10M", test: d =&gt; d.revenue &gt;= 1e6 && d.revenue &lt; 1e7},
    {label: "Over $10M", test: d =&gt; d.revenue &gt;= 1e7}
  ];
  return buckets.map(b =&gt; ({
    bucket: b.label,
    n: withRev.filter(b.test).length,
    revenue: d3.sum(withRev.filter(b.test), d =&gt; d.revenue)
  }));
}







Plot.plot({
  height: 300,
  width: 900,
  marginLeft: 60,
  style: {fontSize: "13px"},
  x: {label: null, domain: sizeBuckets.map(d =&gt; d.bucket)},
  y: {label: "Organizations", grid: true},
  marks: [
    Plot.barY(sizeBuckets, {
      x: "bucket",
      y: "n",
      fill: GU.s1,
      rx: 3,
      insetLeft: 4,
      insetRight: 4,
      tip: true,
      title: d =&gt; `${d.bucket}\n${fnum(d.n)} organizations\nCombined revenue: ${fmoney(d.revenue)}`
    }),
    Plot.textY(sizeBuckets, {
      x: "bucket",
      y: "n",
      text: d =&gt; fnum(d.n),
      dy: -8,
      fill: GU.ink,
      fontSize: 12
    }),
    Plot.ruleY([0], {stroke: "#c3c2b7"})
  ]
})







Plot.plot({
  height: 300,
  width: 900,
  marginLeft: 70,
  style: {fontSize: "13px"},
  x: {label: null, domain: sizeBuckets.map(d =&gt; d.bucket)},
  y: {label: "Combined revenue ($)", grid: true, tickFormat: d =&gt; d3.format("~s")(d).replace("G", "B")},
  marks: [
    Plot.barY(sizeBuckets, {
      x: "bucket",
      y: "revenue",
      fill: GU.s3,
      rx: 3,
      insetLeft: 4,
      insetRight: 4,
      tip: true,
      title: d =&gt; `${d.bucket}\n${fnum(d.n)} organizations\nCombined revenue: ${fmoney(d.revenue)}`
    }),
    Plot.textY(sizeBuckets, {
      x: "bucket",
      y: "revenue",
      text: d =&gt; fmoney(d.revenue),
      dy: -8,
      fill: GU.ink,
      fontSize: 12
    }),
    Plot.ruleY([0], {stroke: "#c3c2b7"})
  ]
})







The two charts share categories but tell opposite stories: organizations cluster at the small end, dollars at the large end. The 73 organizations over $10M — led by Kootenai Health, Gonzaga University, and the region’s credit unions and community health systems — account for the large majority of all nonprofit revenue in the region.

Explore every organization
Search and filter all 5,256 active nonprofits. Click column headers to sort.

